export type TenantScheduleRequest = {
  /**
   * @minLength 1
   * @maxLength 200
   */
  name: string;
  description?: string | undefined;
  enabled?: boolean | undefined;
  /**
   * ScheduledContentProvider registry key.
   *
   * @minLength 1
   * @maxLength 64
   */
  provider_kind: string;
  provider_params?: /**
   * Params passed to the provider. For customer-scoped schedules, the dispatcher merges in {'customer_id': scope_customer.id} before invoking the provider.
   */
  unknown | undefined;
  cadence?: CadenceEnum | undefined;
  day_of_week?:
    | /**
     * 0=Monday ... 6=Sunday. Required when cadence='weekly'.
     *
     * @minimum -2147483648
     * @maximum 2147483647
     */
    (number | null)
    | undefined;
  day_of_month?:
    | /**
     * 1-28 (capped to avoid Feb/short-month gotchas). Required when cadence='monthly'.
     *
     * @minimum -2147483648
     * @maximum 2147483647
     */
    (number | null)
    | undefined;
  time_of_day?: /**
   * Local clock time in the schedule's timezone.
   */
  string | undefined;
  timezone?: /**
   * IANA timezone name (e.g. 'America/New_York'). Defaults to UTC; the fire task falls back to tenant.default_timezone if 'UTC' is set and the tenant configured a non-UTC default.
   *
   * @minLength 1
   * @maxLength 64
   */
  string | undefined;
  channels?: /**
   * List of channel codes, e.g. ['email']. Email-only at launch.
   */
  unknown | undefined;
  recipient_users?: Array<number> | undefined;
  recipient_groups?: Array<string> | undefined;
};
export type TimeEntryRequest = {
  entry_type: TimeEntryTypeEnum;
  start_time: string;
  end_time?: (string | null) | undefined;
  part?: (string | null) | undefined;
  work_order?: (string | null) | undefined;
  step?: (string | null) | undefined;
  equipment?: (string | null) | undefined;
  work_center?: (string | null) | undefined;
  notes?: string | undefined;
  downtime_reason?: /**
   * @maxLength 100
   */
  string | undefined;
  approved?: boolean | undefined;
  archived?: boolean | undefined;
};
export type UserDetail = {
  id: number;
  /**
   * Required. 150 characters or fewer. Letters, digits and @/./+/-/_ only.
   *
   * @maxLength 150
   * @pattern ^[\w.@+-]+$
   */
  username: string;
  first_name?:
    | /**
     * @maxLength 150
     */
    (string | null)
    | undefined;
  last_name?:
    | /**
     * @maxLength 150
     */
    (string | null)
    | undefined;
  email?: /**
   * @maxLength 254
   */
  string | undefined;
  is_staff?: /**
   * Designates whether the user can log into this admin site.
   */
  boolean | undefined;
  is_active?: /**
   * Designates whether this user should be treated as active. Unselect this instead of deleting accounts.
   */
  boolean | undefined;
  date_joined: string;
  parent_company: Company;
  user_type: string;
  user_type_display: string;
};
export type WorkOrder = {
  id: string;
  /**
   * @maxLength 50
   */
  ERP_id: string;
  workorder_status?: WorkOrderStatusEnum | undefined;
  priority?: /**
     * Work order priority. Lower number = higher priority for scheduling.
    
    * `1` - Urgent
    * `2` - High
    * `3` - Normal
    * `4` - Low
     *
     * @minimum -2147483648
     * @maximum 2147483647
     */
  WorkOrderPriorityEnum | undefined;
  quantity?: /**
   * @minimum -2147483648
   * @maximum 2147483647
   */
  number | undefined;
  related_order?: (string | null) | undefined;
  related_order_info: {};
  related_order_detail: {};
  process?: (string | null) | undefined;
  process_info: {};
  expected_completion?: (string | null) | undefined;
  expected_duration?: (string | null) | undefined;
  true_completion?: (string | null) | undefined;
  true_duration?: (string | null) | undefined;
  notes?: (string | null) | undefined;
  parts_summary: {};
  current_hold: {};
  parent_workorder_id: string | null;
  split_reason: SplitReasonEnum | NullEnum | null;
  split_at: string | null;
  child_count: number;
  created_at: string;
  updated_at: string;
  archived?: boolean | undefined;
};
