// Helper function to get CSRF token from cookies
function getCsrfToken(): string | null {
  const name = "csrftoken=";
  const decodedCookie = decodeURIComponent(document.cookie);
  const cookies = decodedCookie.split(";");
  for (let cookie of cookies) {
    cookie = cookie.trim();
    if (cookie.indexOf(name) === 0) {
      return cookie.substring(name.length);
    }
  }
  return null;
}

// Use VITE_API_TARGET environment variable for production builds
// In development with Vite dev server, don't set base URL to rely on Vite proxy
// In production, this will be replaced at build time with the actual backend URL
const BASE_URL = import.meta.env.VITE_API_TARGET;

export const api = BASE_URL
  ? new Zodios(BASE_URL, endpoints, {
      axiosConfig: {
        withCredentials: true,
        paramsSerializer: (params) =>
          qs.stringify(params, { arrayFormat: "repeat" }),
        headers: {
          "X-CSRFToken": getCsrfToken() || "",
        },
      },
    })
  : new Zodios(endpoints, {
      axiosConfig: {
        withCredentials: true,
        paramsSerializer: (params) =>
          qs.stringify(params, { arrayFormat: "repeat" }),
        headers: {
          "X-CSRFToken": getCsrfToken() || "",
        },
      },
    });

// Axios interceptor to refresh CSRF token before each request
api.axios.interceptors.request.use((config) => {
  const csrfToken = getCsrfToken();
  if (csrfToken && config.headers) {
    config.headers["X-CSRFToken"] = csrfToken;
  }
  return config;
});

// Surface Zodios response-validation failures in the browser console.
//
// Without this hook, schema mismatches (frontend Zod schema rejects a
// shape the backend actually returned) bubble up to React Query as an
// opaque rejected promise. The data appears "missing" with no clue
// why — the failing endpoint and the offending field never make it
// to the console unless a caller specifically logs them.
//
// `ZodiosError` is thrown when response validation fails. Its `cause`
// is the underlying `ZodError` with the path + reason, and `config`
// has the request URL. Log both so the failing endpoint is obvious.
function logZodiosResponseValidation(error: unknown): void {
  if (error instanceof ZodiosError && error.cause instanceof ZodError) {
    const method = (error.config?.method ?? "get").toUpperCase();
    const url = error.config?.url ?? "<unknown>";
    // eslint-disable-next-line no-console
    console.error(`[Zodios] Response validation failed for ${method} ${url}`, {
      issues: error.cause.issues,
      received: (error as { data?: unknown }).data,
    });
  }
}

api.axios.interceptors.response.use(
  (response) => response,
  (error) => {
    logZodiosResponseValidation(error);
    return Promise.reject(error);
  }
);

export function createApiClient(baseUrl: string, options?: ZodiosOptions) {
  return new Zodios(baseUrl, endpoints, {
    axiosConfig: {
      withCredentials: true,
      ...options?.axiosConfig,
      paramsSerializer: (params) =>
        qs.stringify(params, { arrayFormat: "repeat" }),
      headers: {
        "X-CSRFToken": getCsrfToken() || "",
        ...options?.axiosConfig?.headers,
      },
    },
    ...options,
  });
}
